dag_dot:
digraph {
    /* Exogenous (unobserved) */
    U_market [label="U_market", observed="no"];
    U_user [label="U_user", observed="no"];

    /* Observed */
    context [label="Context"];
    user [label="User"];
    campaign [label="Campaign"];
    floor [label="Floor Price"];
    market_price [label="Market Price"];
    bid [label="Bid Price"];
    win [label="Win"];
    payment [label="Payment"];
    click [label="Click"];
    value [label="V(x)"];
    surplus [label="Surplus"];

    /* Exogenous -> Observed */
    U_market -> market_price;
    U_user -> user;

    /* Context -> Market */
    context -> market_price;

    /* Bidding decision */
    campaign -> bid;
    context -> bid;
    user -> bid;

    /* Auction outcome */
    bid -> win;
    market_price -> win;
    floor -> win;
    context -> floor;

    /* Two channels to surplus */
    bid -> payment;
    win -> payment;

    /* Click & Value */
    win -> click;
    user -> click;
    context -> click;

    click -> value;
    user -> value;
    context -> value;
    campaign -> value;

    /* Surplus composition */
    value -> surplus;
    payment -> surplus;
    win -> surplus;
}
